settings.customCSS:
/* ── Badge: uppercase eyebrow ── */
& [data-field-id="section-header"] span {
  text-transform: uppercase;
  font-size: 12px !important;
  font-weight: 700 !important;
  letter-spacing: 1.5px;
  border: none !important;
  padding: 0 !important;
  margin-bottom: 12px;
}

/* ── Heading: clamp size, 800 weight, tight tracking ── */
& [data-field-id="section-header"] h2 {
  font-size: clamp(28px, 4vw, 44px) !important;
  font-weight: 800 !important;
  letter-spacing: -0.025em;
}

/* ── Description: 16px, margin-top 10px ── */
& [data-field-id="section-header"] p {
  font-size: 16px !important;
  margin-top: 10px;
}

/* ── Category card header: 20px margin-bottom ── */
& .flex.items-start.gap-3.mb-4 {
  padding-bottom: 16px;
  border-bottom: 1px solid rgba(14, 17, 9, 0.1);
  margin-bottom: 20px !important;
  gap: 12px !important;
}

/* ── Category icon: 42x42, 11px radius ── */
& .flex.items-start.gap-3.mb-4 .shrink-0 {
  width: 42px !important;
  height: 42px !important;
  min-width: 42px !important;
  border-radius: 11px !important;
}

/* ── Category name: Outfit, 15px, 800 ── */
& .flex.items-start.gap-3.mb-4 h3 {
  font-family: var(--font-heading);
  font-size: 15px !important;
  font-weight: 800 !important;
  color: #0e1109 !important;
  margin-bottom: 3px;
}

/* ── Category tagline: 11px ── */
& .flex.items-start.gap-3.mb-4 p {
  font-size: 11px !important;
  color: #8a9086 !important;
  line-height: 1.4;
}

/* ── Service row: 13px font, left accent bar + smooth hover ── */
& a.group {
  position: relative;
  overflow: hidden;
  font-size: 13px !important;
  border-bottom: 1px solid rgba(14, 17, 9, 0.06);
  border-radius: 7px;
  padding: 8px 10px !important;
  transition: background 0.2s ease, padding-left 0.25s cubic-bezier(0.16, 1, 0.3, 1);
}
& a.group:last-child {
  border-bottom: none;
}

/* ── Service name: default style ── */
& a.group span:first-child {
  font-weight: 500;
  font-size: 13px !important;
  color: #1a1f16 !important;
  transition: color 0.2s ease, font-weight 0.2s ease;
}

/* ── Price: heading font, 13px, bold ── */
& a.group span:last-child {
  font-family: var(--font-heading);
  font-size: 13px !important;
  font-weight: 700 !important;
  white-space: nowrap;
  margin-left: 8px;
  transition: transform 0.2s ease;
}

/* Left accent bar (hidden by default) */
& a.group::before {
  content: '';
  position: absolute;
  left: 0;
  top: 0;
  bottom: 0;
  width: 3px;
  border-radius: 0 2px 2px 0;
  transform: scaleY(0);
  transform-origin: center;
  transition: transform 0.3s cubic-bezier(0.16, 1, 0.3, 1);
}

& a.group:hover {
  padding-left: 18px !important;
}
& a.group:hover::before {
  transform: scaleY(1);
}

/* Service name hover: bolder + darker */
& a.group:hover span:first-child {
  font-weight: 600;
  color: #0e1109 !important;
}

/* Price hover: slight scale */
& a.group:hover span:last-child {
  transform: scale(1.06);
}

/* ── Card padding: 26px 22px ── */
& [data-field-id="cards"] > div {
  padding: 26px 22px !important;
}

/* ═══ Category 1: Formation & Legal — CORAL #e84c1e ═══ */
& [data-field-id="cards"] > div:nth-child(1) a.group::before {
  background: #e84c1e;
}
& [data-field-id="cards"] > div:nth-child(1) a.group:hover {
  background: rgba(232, 76, 30, 0.06);
}
& [data-field-id="cards"] > div:nth-child(1) a.group span:last-child {
  color: #e84c1e !important;
}

/* ═══ Category 2: Compliance & Documents — FOREST #1b3a2d ═══ */
& [data-field-id="cards"] > div:nth-child(2) a.group::before {
  background: #1b3a2d;
}
& [data-field-id="cards"] > div:nth-child(2) a.group:hover {
  background: rgba(42, 94, 62, 0.06);
}
& [data-field-id="cards"] > div:nth-child(2) a.group span:last-child {
  color: #1b3a2d !important;
}

/* ═══ Category 3: E-Commerce Setup — BLUE #0064dc ═══ */
& [data-field-id="cards"] > div:nth-child(3) a.group::before {
  background: #0064dc;
}
& [data-field-id="cards"] > div:nth-child(3) a.group:hover {
  background: rgba(0, 100, 220, 0.06);
}
& [data-field-id="cards"] > div:nth-child(3) a.group span:last-child {
  color: #0064dc !important;
}

/* ═══ Category 4: Tax & Finance — PURPLE #7c3aed ═══ */
& [data-field-id="cards"] > div:nth-child(4) a.group::before {
  background: #7c3aed;
}
& [data-field-id="cards"] > div:nth-child(4) a.group:hover {
  background: rgba(124, 58, 237, 0.06);
}
& [data-field-id="cards"] > div:nth-child(4) a.group span:last-child {
  color: #7c3aed !important;
}

/* ═══ Per-category icon colors ═══ */
& [data-field-id="cards"] > div:nth-child(1) .flex.items-start.gap-3.mb-4 .shrink-0 {
  background: rgba(232, 76, 30, 0.08) !important;
}
& [data-field-id="cards"] > div:nth-child(1) .flex.items-start.gap-3.mb-4 .shrink-0 svg {
  color: #e84c1e !important;
}
& [data-field-id="cards"] > div:nth-child(2) .flex.items-start.gap-3.mb-4 .shrink-0 {
  background: rgba(27, 58, 45, 0.08) !important;
}
& [data-field-id="cards"] > div:nth-child(2) .flex.items-start.gap-3.mb-4 .shrink-0 svg {
  color: #1b3a2d !important;
}
& [data-field-id="cards"] > div:nth-child(3) .flex.items-start.gap-3.mb-4 .shrink-0 {
  background: rgba(0, 100, 220, 0.08) !important;
}
& [data-field-id="cards"] > div:nth-child(3) .flex.items-start.gap-3.mb-4 .shrink-0 svg {
  color: #0064dc !important;
}
& [data-field-id="cards"] > div:nth-child(4) .flex.items-start.gap-3.mb-4 .shrink-0 {
  background: rgba(124, 58, 237, 0.08) !important;
}
& [data-field-id="cards"] > div:nth-child(4) .flex.items-start.gap-3.mb-4 .shrink-0 svg {
  color: #7c3aed !important;
}

/* Overlay text 04 at bottom-right */
&::after { content: "04"; position: absolute; right: -20px; bottom: 20px; font-family: var(--font-heading), sans-serif; font-size: 200px; font-weight: 900; color: rgba(27,58,45,0.04); pointer-events: none; line-height: 1; }
/* Badge: padding/border cleanup */
& [data-field-id="badge"] { padding: 0 !important; border: none !important; }
/* Heading: whitespace for line breaks */
& [data-field-id="heading"] { white-space: pre-line; }
/* Step card horizontal padding */
& [data-field-id="steps"] > div { padding: 0 20px; text-align: center; }
/* Continuous dashed connector line through circles */
& [data-field-id="steps"]::before { content: ""; position: absolute; top: 40px; left: 12%; right: 12%; height: 0; border-top: 2px dashed rgba(27,58,45,0.15); pointer-events: none; }
/* Icon circle: z-index above line + shadow + hover */
& [data-field-id="steps"] .group > div:first-child > div:first-child { position: relative; z-index: 2; box-shadow: 0 4px 16px rgba(0,0,0,0.05); transition: all 0.4s cubic-bezier(.16,1,.3,1) !important; }
/* Icon hover: forest green bg */
& [data-field-id="steps"] .group:hover > div:first-child > div:first-child { background-color: #1b3a2d !important; border-color: #1b3a2d !important; box-shadow: 0 8px 28px rgba(27,58,45,0.2); }
/* Icon SVG hover: cream */
& [data-field-id="steps"] .group:hover > div:first-child > div:first-child svg { color: #faf8f4 !important; }
/* Step titles: use heading font */
& [data-field-id="steps"] h3 { font-family: var(--font-heading) !important; }
/* Hide connector and adjust padding on tablet/mobile */
@media (max-width: 1023px) { & [data-field-id="steps"]::before { display: none; } & [data-field-id="steps"] > div { padding: 0 !important; } }

/* Bento Grid */
& [data-field-id='posts'] { grid-template-columns: 1.15fr 1fr 1fr !important; grid-template-rows: 1fr 1fr; gap: 20px !important; }

/* All cards base */
& [data-field-id='posts'] > div > a { border-radius: 20px !important; border: 1px solid rgba(14,17,9,0.1) !important; position: relative; overflow: hidden; transition: transform 0.35s cubic-bezier(0.4,0,0.2,1), box-shadow 0.35s, border-color 0.35s; }
& [data-field-id='posts'] > div > a:hover { transform: translateY(-6px) !important; box-shadow: 0 20px 40px rgba(0,0,0,0.06); border-color: transparent !important; }

/* Accent line bottom */
& [data-field-id='posts'] > div > a::after { content: ''; position: absolute; bottom: 0; left: 0; width: 0; height: 3px; background: #e84c1e; border-radius: 0 3px 0 0; transition: width 0.45s cubic-bezier(0.4,0,0.2,1); z-index: 10; }
& [data-field-id='posts'] > div > a:hover::after { width: 100%; }

/* Title typography */
& [data-field-id='posts'] h3 { font-family: var(--font-heading) !important; font-weight: 800 !important; font-size: 17px !important; letter-spacing: -0.02em; line-height: 1.3 !important; margin-bottom: 10px; transition: color 0.3s; }

/* === Featured card === */
& [data-field-id='posts'] > div:first-child { grid-row: 1 / -1; }
& [data-field-id='posts'] > div:first-child > a { background: #0f2318 !important; border-color: transparent !important; height: 100%; }
& [data-field-id='posts'] > div:first-child > a::after { height: 4px; background: #ff6a3d; }
& [data-field-id='posts'] > div:first-child > a:hover { box-shadow: 0 24px 50px rgba(0,0,0,0.2); }

/* Featured image as bg overlay */
& [data-field-id='posts'] > div:first-child > a > div:first-child { position: absolute !important; inset: 0 !important; width: 100% !important; height: 100% !important; aspect-ratio: unset !important; z-index: 0; border-radius: 0 !important; }
& [data-field-id='posts'] > div:first-child > a > div:first-child img { opacity: 0.18 !important; width: 100% !important; height: 100% !important; object-fit: cover !important; transition: opacity 0.5s, transform 0.8s cubic-bezier(0.4,0,0.2,1) !important; transform: none !important; }
& [data-field-id='posts'] > div:first-child > a:hover > div:first-child img { opacity: 0.25 !important; transform: scale(1.04) !important; }
& [data-field-id='posts'] > div:first-child > a > div:first-child::after { content: ''; position: absolute; inset: 0; background: linear-gradient(to top, #0f2318 25%, rgba(15,35,24,0.6)); z-index: 1; }

/* Featured content layer */
& [data-field-id='posts'] > div:first-child > a > div:nth-child(2) { position: relative; z-index: 2; flex: 1; display: flex; flex-direction: column; padding: 36px 32px 32px !important; }

/* Featured text */
& [data-field-id='posts'] > div:first-child h3 { color: #faf8f4 !important; font-size: clamp(22px, 2.2vw, 28px) !important; }
& [data-field-id='posts'] > div:first-child > a:hover h3 { color: #ff6a3d !important; }
& [data-field-id='posts'] > div:first-child p { color: rgba(250,248,244,0.5) !important; font-size: 15px !important; line-height: 1.75 !important; flex-grow: 1; }

/* Featured badge */
& [data-field-id='posts'] > div:first-child .inline-block.rounded-full { background: rgba(250,248,244,0.1) !important; color: rgba(250,248,244,0.65) !important; border: 1px solid rgba(250,248,244,0.08) !important; }

/* Featured meta footer */
& [data-field-id='posts'] > div:first-child .flex.flex-wrap.items-center { color: rgba(250,248,244,0.35) !important; border-top: 1px solid rgba(255,255,255,0.07); padding-top: 16px; margin-top: auto; }
& [data-field-id='posts'] > div:first-child .flex.flex-wrap.items-center svg { color: rgba(250,248,244,0.35) !important; }

/* Featured arrow circle */
& [data-field-id='posts'] > div:first-child .mt-1 { position: absolute; right: 32px; bottom: 32px; z-index: 3; margin: 0 !important; }
& [data-field-id='posts'] > div:first-child .mt-1 > span { width: 32px; height: 32px; border-radius: 50%; display: flex !important; align-items: center; justify-content: center; background: rgba(250,248,244,0.08); transition: background 0.3s, transform 0.3s; }
& [data-field-id='posts'] > div:first-child .mt-1 svg { color: #ff6a3d !important; width: 15px !important; height: 15px !important; transition: color 0.3s, transform 0.35s cubic-bezier(0.4,0,0.2,1); }
& [data-field-id='posts'] > div:first-child > a:hover .mt-1 > span { background: #e84c1e; }
& [data-field-id='posts'] > div:first-child > a:hover .mt-1 svg { color: #fff !important; transform: translateX(2px); }

/* === Regular cards === */
& [data-field-id='posts'] > div:not(:first-child) > a { background: #fff !important; }

/* Regular image — bleed to edges */
& [data-field-id='posts'] > div:not(:first-child) > a > div:first-child { margin: 0 !important; border-radius: 19px 19px 0 0 !important; height: 150px; aspect-ratio: unset !important; }
& [data-field-id='posts'] > div:not(:first-child) > a > div:first-child img { transition: transform 0.6s cubic-bezier(0.4,0,0.2,1) !important; }
& [data-field-id='posts'] > div:not(:first-child) > a:hover > div:first-child img { transform: scale(1.06) !important; }

/* Regular content */
& [data-field-id='posts'] > div:not(:first-child) > a > div:nth-child(2) { padding: 28px 28px 24px !important; }

/* Regular badge — outline uppercase */
& [data-field-id='posts'] > div:not(:first-child) .inline-block.rounded-full { background: transparent !important; color: #8a9086 !important; border: 1px solid rgba(14,17,9,0.1) !important; font-size: 11px !important; font-weight: 700 !important; text-transform: uppercase; letter-spacing: 0.8px; padding: 4px 12px !important; margin-bottom: 16px; transition: color 0.3s, border-color 0.3s, background 0.3s; }

/* Regular title hover */
& [data-field-id='posts'] > div:not(:first-child):hover h3 { color: #1b3a2d !important; }

/* Regular excerpt */
& [data-field-id='posts'] > div:not(:first-child) p { font-size: 14px !important; color: #4b5249 !important; line-height: 1.65 !important; flex-grow: 1; }

/* Regular footer (meta) */
& [data-field-id='posts'] > div:not(:first-child) .flex.flex-wrap.items-center { border-top: 1px solid rgba(14,17,9,0.1); padding-top: 16px; margin-top: auto; color: #8a9086 !important; font-weight: 500; }

/* Regular arrow circle */
& [data-field-id='posts'] > div:not(:first-child) .mt-1 { position: absolute; right: 28px; bottom: 24px; z-index: 3; margin: 0 !important; }
& [data-field-id='posts'] > div:not(:first-child) .mt-1 > span { width: 32px; height: 32px; border-radius: 50%; display: flex !important; align-items: center; justify-content: center; background: rgba(27,58,45,0.07); flex-shrink: 0; transition: background 0.3s cubic-bezier(0.4,0,0.2,1), transform 0.3s; }
& [data-field-id='posts'] > div:not(:first-child) .mt-1 svg { width: 15px !important; height: 15px !important; color: #1b3a2d !important; transition: color 0.3s, transform 0.35s cubic-bezier(0.4,0,0.2,1); }
& [data-field-id='posts'] > div:not(:first-child) > a:hover .mt-1 > span { background: #1b3a2d; }
& [data-field-id='posts'] > div:not(:first-child) > a:hover .mt-1 svg { color: #faf8f4 !important; transform: translateX(2px); }

/* === Responsive === */
@media (max-width: 1023px) { & [data-field-id='posts'] { grid-template-columns: 1fr 1fr !important; grid-template-rows: auto !important; } & [data-field-id='posts'] > div:first-child { grid-row: auto; grid-column: 1 / -1; } }
@media (max-width: 767px) { & [data-field-id='posts'] { grid-template-columns: 1fr !important; } }
